1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block pattern unchanged when each cell has exactly three neighbors (survival)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    const sortFn = (a: [number, number], b: [number, number]) => a[0] - b[0] || a[1] - b[1];
18	    expect(result.sort(sortFn)).toEqual(block.sort(sortFn));
19	  });
20	  it("should oscillate a blinker pattern producing new cells by reproduction and killing cells by underpopulation", () => {
21	    const verticalBlinker: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const expectedHorizontalBlinker: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(verticalBlinker);
24	    const sortFn = (a: [number, number], b: [number, number]) => a[0] - b[0] || a[1] - b[1];
25	    expect(result.sort(sortFn)).toEqual(expectedHorizontalBlinker.sort(sortFn));
26	  });
27	});
